def replace_package(original, replacement):
    if os.path.isdir(original):
        if os.path.isdir(replacement):
            shutil.rmtree(replacement)
        shutil.copytree(original, replacement)
        os.rmdir(original)
    elif os.path.isfile(original):
        copy_package(original, replacement)
        os.remove(original)
    else:
